import os
from google.cloud import storage
from tensorflow.keras.models import load_model

# Get model path from environment variable
MODEL_PATH = os.environ.get('MODEL_PATH')

# Initialize Google Cloud Storage client
client = storage.Client()

def get_latest_model_version(model_path):
    """Fetch the latest model version from cloud storage"""
    bucket_name, model_name = model_path.split('/')
    bucket = client.bucket(bucket_name)
    blobs = list(bucket.list_blobs(prefix=model_name))
    latest_blob = max(blobs, key=lambda x: int(x.name.split('_')[-1]))
    return latest_blob.name

def load_model_from_cloud(model_path):
    """Load ML model from cloud storage"""
    latest_model_version = get_latest_model_version(model_path)
    blob = client.bucket(model_path.split('/')[0]).blob(latest_model_version)
    model_data = blob.download_as_string()
    return load_model(model_data)

# Load the latest model version on startup
model = load_model_from_cloud(MODEL_PATH)